<div class="container">
    <canvas id="aquariumCanvas" width="1000" height="600"></canvas>
    <div class="info">
        <span><i>🐠</i> 点击撒食</span>
        <span><i>🍕</i> 鱼食 <span id="foodCount">0</span></span>
        <button id="clearFoodBtn">✕ 清空食物</button>
    </div>
</div>
<script>
    (function() {
        const canvas = document.getElementById('aquariumCanvas');
        const ctx = canvas.getContext('2d');
        const foodCountSpan = document.getElementById('foodCount');

        // ---------- 尺寸 ----------
        const W = 1000, H = 600;
        canvas.width = W; canvas.height = H;

        // ---------- 鱼参数 ----------
        const FISH_COUNT = 14;
        const MAX_SPEED = 1.2;
        const EAT_DISTANCE = 18;      // 鱼吃掉食物的距离
        const CHASE_STRENGTH = 0.022; // 追食加速度系数
        const FREE_WANDER_STRENGTH = 0.006;

        // ---------- 鱼群数据 ----------
        let fishes = [];
        // 食物数据
        let foods = [];

        // ---------- 工具函数 ----------
        function rand(min, max) { return Math.random() * (max - min) + min; }

        // 生成一条新鱼 (带颜色/大小)
        function createFish(x, y) {
            const hue = rand(0, 360);
            const sat = rand(60, 95);
            const light = rand(45, 75);
            const size = rand(8, 16);      // 鱼身长度
            return {
                x: x ?? rand(60, W - 60),
                y: y ?? rand(60, H - 60),
                vx: rand(-0.6, 0.6),
                vy: rand(-0.6, 0.6),
                size: size,
                hue: hue,
                sat: sat,
                light: light,
                tailPhase: rand(0, Math.PI * 2),
                // 独特游动偏移
                wobbleOffset: rand(0, 10),
                wobbleSpeed: rand(0.02, 0.05),
            };
        }

        // 初始化鱼群
        function initFishes(count) {
            fishes = [];
            for (let i = 0; i < count; i++) {
                fishes.push(createFish());
            }
        }
        initFishes(FISH_COUNT);

        // ---------- 食物 ----------
        function addFood(x, y) {
            if (x < 0 || x > W || y < 0 || y > H) return;
            const food = {
                x: Math.min(W - 6, Math.max(6, x)),
                y: Math.min(H - 6, Math.max(6, y)),
                radius: 4 + Math.random() * 2,
                life: 1.0,        // 缓慢消失 (视觉淡出)
                birth: performance.now(),
            };
            foods.push(food);
            updateFoodCount();
        }

        function clearAllFood() {
            foods = [];
            updateFoodCount();
        }

        function updateFoodCount() {
            foodCountSpan.textContent = foods.length;
        }

        // ---------- 鱼逻辑：寻找最近食物 ----------
        function findNearestFood(fish) {
            let nearest = null;
            let minDist2 = Infinity;
            for (let i = 0; i < foods.length; i++) {
                const f = foods[i];
                const dx = f.x - fish.x;
                const dy = f.y - fish.y;
                const d2 = dx * dx + dy * dy;
                if (d2 < minDist2) {
                    minDist2 = d2;
                    nearest = f;
                }
            }
            return nearest;
        }

        // ---------- 更新每条鱼 ----------
        function updateFish(fish) {
            // 1. 追食逻辑
            const targetFood = findNearestFood(fish);
            let ax = 0, ay = 0;
            const baseSpeed = 0.4 + fish.size / 22; // 大鱼稍微快一点

            if (targetFood) {
                // 有食物：朝食物加速
                const dx = targetFood.x - fish.x;
                const dy = targetFood.y - fish.y;
                const dist = Math.hypot(dx, dy);
                if (dist < EAT_DISTANCE) {
                    // 吃掉食物！
                    const idx = foods.indexOf(targetFood);
                    if (idx !== -1) {
                        foods.splice(idx, 1);
                        updateFoodCount();
                        // 吃到了，稍微减慢并随机转向 (欢快效果)
                        fish.vx *= 0.6;
                        fish.vy *= 0.6;
                        // 加点随机抖动
                        fish.vx += rand(-0.3, 0.3);
                        fish.vy += rand(-0.3, 0.3);
                    }
                } else {
                    // 追逐
                    const normX = dx / dist;
                    const normY = dy / dist;
                    const chaseAccel = CHASE_STRENGTH * (0.8 + fish.size * 0.02);
                    ax += normX * chaseAccel;
                    ay += normY * chaseAccel;
                    // 增加一点速度上限 (鱼兴奋)
                    fish.vx += ax;
                    fish.vy += ay;
                }
            } else {
                // 没有食物：自由漫游 + 边界回避 + 轻微聚集
                // 漫游 (正弦扰动)
                const wobble = Math.sin(performance.now() * fish.wobbleSpeed + fish.wobbleOffset);
                ax += Math.cos(fish.tailPhase + wobble) * FREE_WANDER_STRENGTH;
                ay += Math.sin(fish.tailPhase + wobble * 0.7) * FREE_WANDER_STRENGTH;

                // 鱼群微弱聚集 (避免太散)
                let sumX = 0, sumY = 0, count = 0;
                for (let other of fishes) {
                    if (other === fish) continue;
                    const dx = other.x - fish.x;
                    const dy = other.y - fish.y;
                    const dist2 = dx*dx + dy*dy;
                    if (dist2 < 180*180 && dist2 > 1) {
                        sumX += dx;
                        sumY += dy;
                        count++;
                    }
                }
                if (count > 0) {
                    const attractStrength = 0.0008;
                    ax += (sumX / count) * attractStrength;
                    ay += (sumY / count) * attractStrength;
                }

                fish.vx += ax;
                fish.vy += ay;
            }

            // 边界回避 (柔软推力)
            const margin = 40;
            const borderForce = 0.12;
            if (fish.x < margin) fish.vx += borderForce * (1 - fish.x / margin);
            if (fish.x > W - margin) fish.vx -= borderForce * (1 - (W - fish.x) / margin);
            if (fish.y < margin) fish.vy += borderForce * (1 - fish.y / margin);
            if (fish.y > H - margin) fish.vy -= borderForce * (1 - (H - fish.y) / margin);

            // 限制速度范围
            const speed = Math.hypot(fish.vx, fish.vy);
            const maxSpd = MAX_SPEED + (fish.size * 0.04);
            if (speed > maxSpd) {
                fish.vx = (fish.vx / speed) * maxSpd;
                fish.vy = (fish.vy / speed) * maxSpd;
            }
            if (speed < 0.2 && !targetFood) {
                // 防止完全静止
                fish.vx += rand(-0.04, 0.04);
                fish.vy += rand(-0.04, 0.04);
            }

            // 更新位置
            fish.x += fish.vx;
            fish.y += fish.vy;

            // 硬边界钳位 (不让鱼出去)
            fish.x = Math.min(W - 6, Math.max(6, fish.x));
            fish.y = Math.min(H - 6, Math.max(6, fish.y));

            // 更新尾巴相位 (动画用)
            fish.tailPhase += 0.04 + speed * 0.04;
        }

        // ---------- 绘制水族箱 ----------
        function drawScene() {
            ctx.clearRect(0, 0, W, H);

            // 1. 背景纹理 (水波纹)
            const grad = ctx.createRadialGradient(200, 150, 30, 400, 300, 800);
            grad.addColorStop(0, '#256682');
            grad.addColorStop(0.4, '#143c52');
            grad.addColorStop(1, '#0a1f2f');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, W, H);

            // 光线/水纹 (装饰)
            ctx.globalAlpha = 0.06;
            for (let i = 0; i < 12; i++) {
                ctx.beginPath();
                ctx.arc(120 + i * 80, 60 + i * 30, 180 + i * 20, 0, Math.PI * 2);
                ctx.fillStyle = '#9fc7e0';
                ctx.fill();
            }
            ctx.globalAlpha = 0.08;
            ctx.fillStyle = '#ffffff10';
            for (let i = 0; i < 8; i++) {
                ctx.beginPath();
                ctx.ellipse(200 + i * 110, 400 + i * 20, 140, 30, 0.2, 0, Math.PI * 2);
                ctx.fill();
            }
            ctx.globalAlpha = 1.0;

            // 2. 绘制食物 (发光)
            for (let f of foods) {
                const rad = f.radius * (0.8 + 0.2 * Math.sin(performance.now() * 0.005 + f.x));
                const gradient = ctx.createRadialGradient(f.x-2, f.y-2, 1, f.x, f.y, rad+4);
                gradient.addColorStop(0, '#fdea8f');
                gradient.addColorStop(0.5, '#e8b63b');
                gradient.addColorStop(1, '#b67f1a80');
                ctx.shadowColor = '#fcd25a';
                ctx.shadowBlur = 18;
                ctx.beginPath();
                ctx.arc(f.x, f.y, rad, 0, Math.PI * 2);
                ctx.fillStyle = gradient;
                ctx.fill();
                // 内亮点
                ctx.shadowBlur = 8;
                ctx.beginPath();
                ctx.arc(f.x-1, f.y-1, rad*0.5, 0, 2 * Math.PI);
                ctx.fillStyle = '#fff8e0';
                ctx.fill();
            }
            ctx.shadowBlur = 0;
            ctx.shadowColor = 'transparent';

            // 3. 绘制鱼群
            for (let fish of fishes) {
                const angle = Math.atan2(fish.vy, fish.vx);
                const size = fish.size;
                const bodyLength = size * 1.4;
                const bodyHeight = size * 0.7;

                ctx.save();
                ctx.translate(fish.x, fish.y);
                ctx.rotate(angle);

                // 鱼身渐变
                const gradient = ctx.createLinearGradient(-bodyLength*0.6, 0, bodyLength*0.6, 0);
                const baseColor = `hsl(${fish.hue}, ${fish.sat}%, ${fish.light}%)`;
                const lightColor = `hsl(${fish.hue}, ${fish.sat-10}%, ${fish.light+18}%)`;
                const darkColor = `hsl(${fish.hue}, ${fish.sat+5}%, ${fish.light-12}%)`;
                gradient.addColorStop(0, darkColor);
                gradient.addColorStop(0.4, baseColor);
                gradient.addColorStop(0.8, lightColor);
                gradient.addColorStop(1, darkColor);

                // 鱼身 (椭圆)
                ctx.shadowColor = 'rgba(0,30,40,0.5)';
                ctx.shadowBlur = 12;
                ctx.beginPath();
                ctx.ellipse(0, 0, bodyLength/2, bodyHeight/2, 0, 0, Math.PI * 2);
                ctx.fillStyle = gradient;
                ctx.fill();

                // 鳞片高光
                ctx.shadowBlur = 6;
                ctx.beginPath();
                ctx.ellipse(6, -2, bodyLength*0.18, bodyHeight*0.15, 0.1, 0, Math.PI*2);
                ctx.fillStyle = `hsl(${fish.hue}, ${fish.sat-20}%, ${fish.light+25}%)`;
                ctx.globalAlpha = 0.3;
                ctx.fill();
                ctx.globalAlpha = 1.0;

                // 尾巴 (随相位摆动)
                const tailWag = Math.sin(fish.tailPhase) * 0.2 + 0.3;
                ctx.shadowBlur = 10;
                ctx.beginPath();
                ctx.moveTo(-bodyLength/2 - 2, 0);
                ctx.quadraticCurveTo(-bodyLength/2 - 8 - tailWag*4, -bodyHeight*0.8, 
                                     -bodyLength/2 - 6 - tailWag*8, 0);
                ctx.quadraticCurveTo(-bodyLength/2 - 8 - tailWag*4, bodyHeight*0.8, 
                                     -bodyLength/2 - 2, 0);
                ctx.fillStyle = `hsl(${fish.hue}, ${fish.sat-5}%, ${fish.light-15}%)`;
                ctx.fill();

                // 眼睛
                ctx.shadowBlur = 0;
                ctx.beginPath();
                ctx.arc(bodyLength*0.25, -bodyHeight*0.1, size*0.17, 0, Math.PI*2);
                ctx.fillStyle = '#0c1a22';
                ctx.fill();
                ctx.beginPath();
                ctx.arc(bodyLength*0.3, -bodyHeight*0.1, size*0.09, 0, Math.PI*2);
                ctx.fillStyle = '#d8ecf0';
                ctx.fill();
                ctx.beginPath();
                ctx.arc(bodyLength*0.27, -bodyHeight*0.12, size*0.04, 0, Math.PI*2);
                ctx.fillStyle = '#ffffff';
                ctx.fill();

                // 背鳍/腹鳍 (小装饰)
                ctx.beginPath();
                ctx.moveTo(-2, -bodyHeight/2 + 2);
                ctx.lineTo(6, -bodyHeight/2 - 5);
                ctx.lineTo(12, -bodyHeight/2 + 2);
                ctx.fillStyle = `hsl(${fish.hue}, ${fish.sat-10}%, ${fish.light-8}%)`;
                ctx.globalAlpha = 0.5;
                ctx.fill();

                ctx.beginPath();
                ctx.moveTo(-2, bodyHeight/2 - 2);
                ctx.lineTo(6, bodyHeight/2 + 5);
                ctx.lineTo(12, bodyHeight/2 - 2);
                ctx.fill();
                ctx.globalAlpha = 1.0;

                ctx.restore();
            }

            // 绘制一些气泡 (氛围)
            ctx.shadowBlur = 15;
            ctx.shadowColor = '#8ac0dd40';
            for (let i = 0; i < 5; i++) {
                const x = (Math.sin(performance.now()*0.002 + i*2) * 0.5 + 0.5) * W;
                const y = (Math.cos(performance.now()*0.003 + i*3) * 0.3 + 0.5) * H;
                const r = 3 + i * 2.5;
                ctx.beginPath();
                ctx.arc(x, y, r, 0, Math.PI*2);
                ctx.fillStyle = 'rgba(200,235,255,0.08)';
                ctx.fill();
                ctx.beginPath();
                ctx.arc(x-2, y-2, r*0.3, 0, Math.PI*2);
                ctx.fillStyle = 'rgba(255,255,255,0.15)';
                ctx.fill();
            }
            ctx.shadowBlur = 0;
        }

        // ---------- 动画循环 ----------
        function animate() {
            // 更新所有鱼
            for (let fish of fishes) {
                updateFish(fish);
            }

            // 移除生命周期过长的食物 (逐渐淡出, 暂时不删除, 但保留寿命衰减视觉效果)
            // 我们也可以让食物慢慢变小，但为了简洁，这里保留食物直到被吃或手动清除
            // (增加一点缓慢消失: 超过25秒自动消失)
            const now = performance.now();
            foods = foods.filter(f => now - f.birth < 25000);
            updateFoodCount();

            drawScene();
            requestAnimationFrame(animate);
        }

        // ---------- 交互：点击投放食物 ----------
        canvas.addEventListener('click', (e) => {
            const rect = canvas.getBoundingClientRect();
            const scaleX = canvas.width / rect.width;
            const scaleY = canvas.height / rect.height;
            const mouseX = (e.clientX - rect.left) * scaleX;
            const mouseY = (e.clientY - rect.top) * scaleY;
            // 投放 2~3 粒小食物 (更有满足感)
            const count = 2 + Math.floor(Math.random() * 2);
            for (let i = 0; i < count; i++) {
                addFood(
                    mouseX + rand(-12, 12),
                    mouseY + rand(-8, 8)
                );
            }
        });

        // 清空食物按钮
        document.getElementById('clearFoodBtn').addEventListener('click', () => {
            clearAllFood();
        });

        // 画面自适应保持比例 (让canvas根据CSS缩放)
        function resizeCanvas() {
            // 不做额外操作，由css aspect-ratio处理
        }
        window.addEventListener('resize', resizeCanvas);

        // 启动动画
        animate();
    })();
</script>
</body>
</html>
```
### 交互与生态模拟
您可以通过点击与观察，体验一个微型水族生态的运作。其核心机制围绕鱼的智能行为展开。
1.  **投放与追逐**：点击水族箱任意位置，会撒下数粒鱼食。每条鱼都会智能地寻找并游向离自己最近的那一粒。
2.  **觅食与游动**：当鱼接近鱼食到一定距离时，便会“吃掉”它。在没有食物时，鱼群会恢复自由漫游，并伴有微弱的聚集和边界回避行为，显得更加自然。
3.  **视觉与反馈**：每条鱼都有独特的颜色、大小和游动姿态。界面左上角会实时显示当前剩余鱼食数量，您也可以使用“清空食物”按钮快速重置场景。

这是您要求的单文件 HTML 时钟应用。它包含一个圆形表盘，带有刻度、数字和三根指针，并实时显示中国标准时间与日期，整体风格简洁且富有高级感。
```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no">
    <title>简约 · 北京时区时钟</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }
        body {
            background: #f5f7fc;
            min-height: 100vh;
            display: flex;
            justify-content: center;
            align-items: center;
            font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
            padding: 16px;
            margin: 0;
        }
        .clock-card {
            background: #ffffff;
            border-radius: 48px;
            padding: 30px 30px 40px 30px;
            box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.26), 
                        0 8px 18px rgba(0, 0, 0, 0.08);
            border: 1px solid rgba(220, 225, 235, 0.5);
            transition: box-shadow 0.2s ease;
            max-width: 600px;
            width: 100%;
        }
        .clock-card:hover {
            box-shadow: 0 30px 55px -12px rgba(0, 0, 0, 0.3);
        }
        .clock-container {
            position: relative;
            width: 100%;
            aspect-ratio: 1/1;
            display: flex;
            justify-content: center;
            align-items: center;
        }
        canvas {
            display: block;
            width: 100%;
            height: auto;
            background: #ffffff;
            border-radius: 50%;
            box-shadow: inset 0 2px 8px rgba(0,0,0,0.02), 0 6px 18px rgba(0, 0, 0, 0.05);
            border: 2px solid #1a1e2b;
            touch-action: none;
        }
        /* 日期时间内部显示由canvas绘制，无需额外元素 */
        @media (max-width: 420px) {
            .clock-card {
                padding: 16px 16px 24px 16px;
                border-radius: 32px;
            }
        }
    </style>
</head>
<body>
<div class="clock-card">
    <div class="clock-container">
        <canvas id="clockCanvas" width="600" height="600"></canvas>
    </div>
</div>
<script>
    (function() {
        const canvas = document.getElementById('clockCanvas');
        // 确保canvas尺寸清晰 (物理像素)
        const rect = canvas.getBoundingClientRect();
        const dpr = window.devicePixelRatio || 1;
        // 但我们用固定600x600逻辑尺寸，由CSS缩放，适应所有屏幕
        // 减少复杂缩放干扰，保证锐利：设置canvas宽高为600
        canvas.width = 600;
        canvas.height = 600;
        const ctx = canvas.getContext('2d');

        // 中心点及半径 (基于600尺寸)
        const centerX = 300;
        const centerY = 300;
        const radius = 270;      // 表盘半径
        const innerLabelRadius = 230; // 数字标签半径
        const tickOuterRadius = 282;
        const tickInnerRadius = 262;   // 普通刻度
        const longTickInnerRadius = 248; // 整点刻度 (更粗更长)

        // 平滑运动: 使用 requestAnimationFrame
        let animFrameId = null;

        // 更新时钟绘图 (北京时区)
        function updateClock() {
            // 获取北京时区 (Asia/Shanghai) 日期时间
            const now = new Date();
            // 转换为北京时区时间字符串 (使用 Intl 格式化)
            const options = { timeZone: 'Asia/Shanghai', hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' };
            const timeStr = new Intl.DateTimeFormat('zh-CN', options).format(now);
            // 提取时、分、秒、毫秒 (用于平滑秒针)
            const beijingTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Shanghai' }));
            // 但上面方法会丢失毫秒精度，改用手动计算偏移 
            // 推荐: 计算 UTC 偏移 +8小时, 保留毫秒
            const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
            const beijingOffset = 8 * 3600000; // 东八区
            const beijingDate = new Date(utc + beijingOffset);

            const hours = beijingDate.getHours() % 12;
            const minutes = beijingDate.getMinutes();
            const seconds = beijingDate.getSeconds();
            const milliseconds = beijingDate.getMilliseconds();

            // 平滑秒针角度: 每秒60格, 加上毫秒平滑 (0.5秒=30度, 为了平滑)
            const secondAngle = (seconds + milliseconds / 1000) * 6;  // 每秒6度

            // 分针角度 (受秒针轻微影响, 更平滑)
            const minuteAngle = minutes * 6 + (seconds + milliseconds / 1000) * 0.1; // 每分钟6度 + 每秒0.1度

            // 时针角度 (受分钟影响)
            const hourAngle = hours * 30 + minutes * 0.5 + (seconds + milliseconds / 1000) * (0.5 / 60); // 每小时30度 + 每分钟0.5度

            // ---- 绘制 ----
            ctx.clearRect(0, 0, 600, 600);

            // --- 1. 表盘背景 (白色, 带细微质感) ---
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius + 8, 0, 2 * Math.PI);
            ctx.fillStyle = '#ffffff';
            ctx.shadowColor = 'rgba(0, 0, 0, 0.08)';
            ctx.shadowBlur = 20;
            ctx.shadowOffsetX = 0;
            ctx.shadowOffsetY = 4;
            ctx.fill();
            ctx.shadowColor = 'transparent'; // 重置避免影响后续绘制

            // 描边 (深色边框)
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius + 6, 0, 2 * Math.PI);
            ctx.strokeStyle = '#1a1e2b';
            ctx.lineWidth = 4;
            ctx.stroke();

            // 轻微内阴影 / 3D效果 (白色内圈)
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius - 6, 0, 2 * Math.PI);
            ctx.fillStyle = '#fafcff';
            ctx.shadowColor = 'rgba(0,0,0,0.02)';
            ctx.shadowBlur = 12;
            ctx.shadowOffsetX = 0;
            ctx.shadowOffsetY = 2;
            ctx.fill();
            ctx.shadowColor = 'transparent';

            // --- 2. 刻度 & 数字 ---
            // 先画刻度线 (从12点开始，顺时针)
            for (let i = 0; i < 60; i++) {
                const angle = (i * 6 - 90) * Math.PI / 180; // 从12点 ( -90°)
                const isHour = (i % 5 === 0);
                const innerR = isHour ? longTickInnerRadius : tickInnerRadius;
                const outerR = tickOuterRadius;

                const x1 = centerX + innerR * Math.cos(angle);
                const y1 = centerY + innerR * Math.sin(angle);
                const x2 = centerX + outerR * Math.cos(angle);
                const y2 = centerY + outerR * Math.sin(angle);

                ctx.beginPath();
                ctx.moveTo(x1, y1);
                ctx.lineTo(x2, y2);
                ctx.lineCap = 'round';
                if (isHour) {
                    ctx.strokeStyle = '#1e2433';
                    ctx.lineWidth = 4.4;
                } else {
                    ctx.strokeStyle = '#5a6270';
                    ctx.lineWidth = 2.2;
                }
                ctx.stroke();
            }

            // 绘制数字 (1-12)  更雅致的字体
            ctx.fillStyle = '#1e2433';
            ctx.font = '600 30px "Inter", "SF Pro Display", "Segoe UI", Roboto, Helvetica, Arial, sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            for (let i = 1; i <= 12; i++) {
                const angle = (i * 30 - 90) * Math.PI / 180;
                const labelRadius = innerLabelRadius;
                const x = centerX + labelRadius * Math.cos(angle);
                const y = centerY + labelRadius * Math.sin(angle);
                // 轻微阴影增加层次感
                ctx.shadowColor = 'rgba(0,0,0,0.02)';
                ctx.shadowBlur = 4;
                ctx.fillText(String(i), x, y);
                ctx.shadowColor = 'transparent';
            }

            // --- 3. 内部显示 当前时间和日期 (北京) ---
            // 日期格式化 (北京)
            const dateOptions = { timeZone: 'Asia/Shanghai', year: 'numeric', month: '2-digit', day: '2-digit', weekday: 'short' };
            const dateStr = new Intl.DateTimeFormat('zh-CN', dateOptions).format(beijingDate);
            // 时间字符串 (不含秒) 搭配秒针展示
            const timeOptions = { timeZone: 'Asia/Shanghai', hour12: false, hour: '2-digit', minute: '2-digit' };
            const shortTimeStr = new Intl.DateTimeFormat('zh-CN', timeOptions).format(beijingDate);
            // 组合显示: 日期上行, 时间下行 (或同一行) 在表盘内部
            ctx.shadowColor = 'transparent';
            ctx.fillStyle = '#2a3142';
            ctx.font = '500 20px "Inter", "SF Pro Text", "Segoe UI", sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            // 绘制日期 (居中偏上)
            ctx.fillText(dateStr, centerX, centerY + 52);
            // 绘制时间 (大号)
            ctx.font = '600 44px "Inter", "SF Pro Display", "Segoe UI", sans-serif';
            ctx.fillStyle = '#11161f';
            ctx.fillText(shortTimeStr, centerX, centerY - 2);

            // 小秒点 (装饰)
            ctx.beginPath();
            ctx.arc(centerX + 65, centerY + 50, 3, 0, 2 * Math.PI);
            ctx.fillStyle = '#3f4a5e';
            ctx.fill();

            // --- 4. 绘制指针 (时针、分针、秒针) ---
            // 4.1 时针 (短粗, 圆角)
            const hourLength = 130;
            const hourAngleRad = (hourAngle - 90) * Math.PI / 180;
            ctx.shadowColor = 'rgba(0, 0, 0, 0.1)';
            ctx.shadowBlur = 12;
            ctx.shadowOffsetX = 0;
            ctx.shadowOffsetY = 3;
            ctx.beginPath();
            ctx.moveTo(centerX - 12 * Math.cos((hourAngle - 90) * Math.PI / 180), 
                       centerY - 12 * Math.sin((hourAngle - 90) * Math.PI / 180));
            ctx.lineTo(centerX + hourLength * Math.cos(hourAngleRad), 
                       centerY + hourLength * Math.sin(hourAngleRad));
            ctx.lineWidth = 10;
            ctx.lineCap = 'round';
            ctx.strokeStyle = '#1a1f2b';
            ctx.stroke();

            // 4.2 分针 (稍长, 中等粗细)
            const minuteLength = 190;
            const minuteAngleRad = (minuteAngle - 90) * Math.PI / 180;
            ctx.beginPath();
            ctx.moveTo(centerX - 18 * Math.cos((minuteAngle - 90) * Math.PI / 180), 
                       centerY - 18 * Math.sin((minuteAngle - 90) * Math.PI / 180));
            ctx.lineTo(centerX + minuteLength * Math.cos(minuteAngleRad), 
                       centerY + minuteLength * Math.sin(minuteAngleRad));
            ctx.lineWidth = 6;
            ctx.lineCap = 'round';
            ctx.strokeStyle = '#2b3345';
            ctx.stroke();

            // 4.3 秒针 (细长, 亮色, 带圆心帽)
            const secondLength = 220;
            const secondAngleRad = (secondAngle - 90) * Math.PI / 180;
            ctx.shadowColor = 'rgba(0, 0, 0, 0.12)';
            ctx.shadowBlur = 10;
            ctx.beginPath();
            ctx.moveTo(centerX - 25 * Math.cos((secondAngle - 90) * Math.PI / 180), 
                       centerY - 25 * Math.sin((secondAngle - 90) * Math.PI / 180));
            ctx.lineTo(centerX + secondLength * Math.cos(secondAngleRad), 
                       centerY + secondLength * Math.sin(secondAngleRad));
            ctx.lineWidth = 2.8;
            ctx.lineCap = 'round';
            ctx.strokeStyle = '#c7444a';
            ctx.stroke();

            // 圆心金属帽
            ctx.shadowColor = 'rgba(0,0,0,0.15)';
            ctx.shadowBlur = 12;
            ctx.beginPath();
            ctx.arc(centerX, centerY, 10, 0, 2 * Math.PI);
            ctx.fillStyle = '#1a1e2b';
            ctx.fill();
            ctx.shadowColor = 'transparent';
            ctx.beginPath();
            ctx.arc(centerX, centerY, 5, 0, 2 * Math.PI);
            ctx.fillStyle = '#e8edf5';
            ctx.fill();

            // 清除阴影防止影响下一个周期
            ctx.shadowColor = 'transparent';
            ctx.shadowBlur = 0;
        }

        // 动画循环 (requestAnimationFrame)
        function tick() {
            updateClock();
            animFrameId = requestAnimationFrame(tick);
        }

        // 启动动画
        tick();

        // 窗口 resize 不涉及重绘, 但可考虑防抖 (无操作)
        // 清理动画 (页面卸载)
        window.addEventListener('beforeunload', function() {
            if (animFrameId) {
                cancelAnimationFrame(animFrameId);
                animFrameId = null;
            }
        });

        // 优化: 如果页面隐藏则暂停动画 (可选)
        document.addEventListener('visibilitychange', function() {
            if (document.hidden) {
                if (animFrameId) {
                    cancelAnimationFrame(animFrameId);
                    animFrameId = null;
                }
            } else {
                if (!animFrameId) {
                    animFrameId = requestAnimationFrame(tick);
                }
            }
        });

        // 兼容 Edge 的附加检查 (所有API均支持)
        console.log('时钟已启动 (北京时区)');
    })();
</script>
</body>
</html>
```
### 时钟功能与视觉设计
您可以通过这个应用直观地读取时间。其核心逻辑是精确计算北京时区时间，并驱动指针平滑转动。

-   **时间与指针逻辑**：`updateClock()` 函数会获取当前北京时间，并计算出时针、分针和秒针的精确角度。其中秒针角度融合了毫秒值，实现了平滑的扫秒运动。
-   **表盘与刻度**：代码使用 Canvas 绘制了60个刻度，其中整点刻度更粗、颜色更深。表盘内部还清晰显示了数字、当前时间（时/分）和日期（含星期）。
-   **刷新与性能**：页面使用 `requestAnimationFrame` 驱动时钟刷新，这比 `setInterval` 更节省资源，并能确保动画与屏幕刷新率同步，运行更加流畅。

---

**优化建议：** 您可以根据喜好调整 `radius`（表盘半径）或 `innerLabelRadius`（数字位置）等变量，以微调表盘比例。指针颜色（如 `strokeStyle` 值）也可按需修改。

