<script>
  (function() {
    "use strict";

    // ---------- build scales (60 ticks) ----------
    const scaleLayer = document.getElementById('scaleLayer');
    const fragment = document.createDocumentFragment();
    for (let i = 0; i < 60; i++) {
      const tick = document.createElement('div');
      tick.className = 'tick';
      // hour ticks (0, 5, 10, ... 55) → 12 positions
      if (i % 5 === 0) {
        tick.classList.add('hour-tick');
      }
      // rotation: each tick i * 6°
      const angle = i * 6;
      tick.style.transform = `rotate(${angle}deg)`;
      fragment.appendChild(tick);
    }
    scaleLayer.appendChild(fragment);

    // ---------- build numbers (1–12) ----------
    const numbersLayer = document.getElementById('numbersLayer');
    const radius = 148; // distance from center to number
    const center = 190; // half of 380 (dial size)
    // adjust for responsive: if dial is 320, we compute relative
    const dial = document.getElementById('clockDial');
    let dialSize = 380;

    function placeNumbers(size) {
      const baseRadius = size * 0.39;  // 148 for 380px, 0.3895
      const cx = size / 2;
      const cy = size / 2;

      // clear existing numbers (if any)
      while (numbersLayer.firstChild) {
        numbersLayer.removeChild(numbersLayer.firstChild);
      }

      for (let i = 1; i <= 12; i++) {
        const num = document.createElement('div');
        num.className = 'num';
        num.textContent = i;
        // angle: 12 at top ( -90° ), each hour +30°
        const angleDeg = i * 30 - 90;
        const rad = angleDeg * Math.PI / 180;
        const x = cx + baseRadius * Math.cos(rad);
        const y = cy + baseRadius * Math.sin(rad);
        num.style.left = `${x}px`;
        num.style.top = `${y}px`;
        numbersLayer.appendChild(num);
      }
    }

    // initial placement
    dialSize = dial.offsetWidth || 380;
    placeNumbers(dialSize);

    // resize observer – adjust numbers on resize
    const resizeObserver = new ResizeObserver(entries => {
      for (let entry of entries) {
        const size = entry.contentBoxSize?.[0]?.inlineSize || entry.target.offsetWidth;
        if (size > 0) {
          dialSize = size;
          placeNumbers(size);
        }
      }
    });
    resizeObserver.observe(dial);

    // ---------- clock logic (Beijing Time, UTC+8) ----------
    const hourHand = document.getElementById('hourHand');
    const minuteHand = document.getElementById('minuteHand');
    const secondHand = document.getElementById('secondHand');
    const timeDisplay = document.getElementById('timeDisplay');
    const dateDisplay = document.getElementById('dateDisplay');

    function getBeijingTime() {
      // get real Beijing time via locale string
      const beijingString = new Date().toLocaleString("en-US", { timeZone: "Asia/Shanghai" });
      return new Date(beijingString);
    }

    function updateClock() {
      const now = getBeijingTime();

      const hours = now.getHours();
      const minutes = now.getMinutes();
      const seconds = now.getSeconds();
      const milliseconds = now.getMilliseconds();

      // --- smooth second hand (including millisecond interpolation) ---
      const smoothSeconds = seconds + milliseconds / 1000;
      const secondAngle = smoothSeconds * 6;   // 360° / 60 = 6°

      // minute hand (includes seconds offset for smooth micro movement)
      const minuteAngle = (minutes + seconds / 60) * 6;

      // hour hand (including minutes & seconds for continuous movement)
      const hourAngle = (hours % 12 + minutes / 60 + seconds / 3600) * 30;

      // apply rotations
      secondHand.style.transform = `rotate(${secondAngle}deg)`;
      minuteHand.style.transform = `rotate(${minuteAngle}deg)`;
      hourHand.style.transform = `rotate(${hourAngle}deg)`;

      // --- text: upper (24h format) ---
      const hh = String(hours).padStart(2, '0');
      const mm = String(minutes).padStart(2, '0');
      const ss = String(seconds).padStart(2, '0');
      timeDisplay.textContent = `${hh}:${mm}:${ss}`;

      // --- text: lower (date + day of week) ---
      const year = now.getFullYear();
      const month = String(now.getMonth() + 1).padStart(2, '0');
      const day = String(now.getDate()).padStart(2, '0');
      const weekdays = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
      const weekday = weekdays[now.getDay()];
      dateDisplay.textContent = `${year}.${month}.${day}  ${weekday}`;
    }

    // initial call
    updateClock();

    // smooth loop using requestAnimationFrame (updates every frame ~16ms)
    let lastTimestamp = 0;
    function tickLoop(timestamp) {
      // update only once per frame, no need for delta
      updateClock();
      requestAnimationFrame(tickLoop);
    }
    requestAnimationFrame(tickLoop);

    // (optional) also setInterval fallback – but rAF already does it
    // ensure sometimes even if rAF stutters, but fine.
  })();
</script>
