                {"id": "y", "start": "2026-05-01T09:00:00", "end": "2026-05-01T10:00:00", "value": 3},
                {"id": "z", "start": "2026-05-01T10:00:00", "end": "2026-05-01T11:00:00", "value": 4}
            ],
