<div class="aquarium-wrapper">
    <canvas id="aquariumCanvas" width="900" height="600"></canvas>
    <div class="caption">
        <span><i>🐟</i> 点击投放鱼食</span>
        <span><i>🍕</i> 鱼会追逐最近的食物</span>
    </div>
</div>
<script>
    (function() {
        const canvas = document.getElementById('aquariumCanvas');
        const ctx = canvas.getContext('2d');
        const W = 900, H = 600;

        // ---------- 参数设定 ----------
        const FISH_COUNT = 11;           // 鱼群数量
        const MAX_FOOD = 20;             // 最多同时存在的鱼食
        const EAT_DISTANCE = 12;         // 鱼吃掉食物的距离
        const AVOID_BORDER = 30;         // 离墙距离
        const TURN_SPEED = 0.04;         // 转向平滑系数
        const MAX_SPEED = 1.8;
        const MIN_SPEED = 0.7;

        // ---------- 鱼数据结构 ----------
        let fishes = [];
        // 每条鱼: { x, y, vx, vy, angle, speed, color, size, tailPhase }

        // ---------- 食物数据 ----------
        let foodPellets = [];  // { x, y, radius }

        // ---------- 初始化鱼群 ----------
        function initFish() {
            const palette = [
                '#FF8A9B', '#FFB347', '#6ECB63', '#5DADE2', '#AF7AC5',
                '#F7DC6F', '#85C1E9', '#F1948A', '#82E0AA', '#F8C471',
                '#D7BDE2', '#A3E4D7', '#FAD7A0', '#A9CCE3', '#D5DBDB'
            ];
            for (let i = 0; i < FISH_COUNT; i++) {
                const size = 7 + Math.random() * 11;  // 7~18
                const baseSpeed = MIN_SPEED + Math.random() * (MAX_SPEED - MIN_SPEED);
                // 随机起始位置，避开边界
                const x = AVOID_BORDER + Math.random() * (W - 2 * AVOID_BORDER);
                const y = AVOID_BORDER + Math.random() * (H - 2 * AVOID_BORDER);
                const angle = Math.random() * Math.PI * 2;
                fishes.push({
                    x, y,
                    vx: Math.cos(angle) * baseSpeed,
                    vy: Math.sin(angle) * baseSpeed,
                    angle: angle,
                    speed: baseSpeed,
                    color: palette[i % palette.length],
                    size: size,
                    tailPhase: Math.random() * 100,
                });
            }
        }

        // ---------- 重置/添加食物 ----------
        function addFood(x, y) {
            if (foodPellets.length >= MAX_FOOD) {
                // 移除最旧的一粒
                foodPellets.shift();
            }
            // 避免食物堆叠太夸张 —— 加一点随机偏移，更像撒下
            const offX = (Math.random() - 0.5) * 6;
            const offY = (Math.random() - 0.5) * 6;
            foodPellets.push({
                x: Math.min(W - 5, Math.max(5, x + offX)),
                y: Math.min(H - 5, Math.max(5, y + offY)),
                radius: 3 + Math.random() * 3,  // 3~6
            });
        }

        // ---------- 鱼群逻辑（追逐 + 自由游动）----------
        function updateFish() {
            for (let i = 0; i < fishes.length; i++) {
                const fish = fishes[i];

                // ---- 1. 寻找最近的鱼食 ----
                let targetFood = null;
                let minDist = Infinity;
                for (let j = 0; j < foodPellets.length; j++) {
                    const food = foodPellets[j];
                    const dx = food.x - fish.x;
                    const dy = food.y - fish.y;
                    const dist = dx * dx + dy * dy;
                    if (dist < minDist) {
                        minDist = dist;
                        targetFood = food;
                    }
                }

                // ---- 2. 转向目标（食物 or 自由探索）----
                let targetAngle = fish.angle;
                let isChasing = false;

                if (targetFood) {
                    // 有食物：转向食物
                    const dx = targetFood.x - fish.x;
                    const dy = targetFood.y - fish.y;
                    targetAngle = Math.atan2(dy, dx);
                    isChasing = true;
                } else {
                    // 自由游动：随机轻微转向 + 边界回避
                    // 边界回避优先级更高
                    let turnForce = 0;
                    const margin = AVOID_BORDER + 8;
                    if (fish.x < margin) turnForce += 0.8;
                    else if (fish.x > W - margin) turnForce -= 0.8;
                    if (fish.y < margin) turnForce += 0.4;
                    else if (fish.y > H - margin) turnForce -= 0.4;

                    if (Math.abs(turnForce) > 0.01) {
                        // 有边界压力：计算期望角度
                        const desiredAngle = (fish.x < margin || fish.x > W - margin) ? 
                            (fish.x < margin ? 0 : Math.PI) : fish.angle;
                        const desiredAngleY = (fish.y < margin || fish.y > H - margin) ?
                            (fish.y < margin ? Math.PI/2 : -Math.PI/2) : fish.angle;
                        // 混合角度
                        targetAngle = Math.atan2(
                            (fish.y < margin ? 1 : (fish.y > H - margin ? -1 : Math.sin(fish.angle))),
                            (fish.x < margin ? 1 : (fish.x > W - margin ? -1 : Math.cos(fish.angle)))
                        );
                        // 更柔和的转向
                    } else {
                        // 随机漫游：小幅偏转
                        const noise = (Math.random() - 0.5) * 0.5;
                        targetAngle = fish.angle + noise;
                    }
                }

                // 平滑转向 (lerp angle)
                let diff = targetAngle - fish.angle;
                while (diff > Math.PI) diff -= Math.PI * 2;
                while (diff < -Math.PI) diff += Math.PI * 2;
                fish.angle += diff * TURN_SPEED;

                // ---- 3. 根据是否追逐调整速度 ----
                if (isChasing) {
                    // 追逐时加速，但不超过上限
                    fish.speed = Math.min(MAX_SPEED, fish.speed + 0.04);
                } else {
                    // 自由游动：恢复基础速度并加一点变化
                    const base = MIN_SPEED + (fish.size / 20) * 0.6; // 大鱼稍慢
                    fish.speed += (base - fish.speed) * 0.02 + (Math.random() - 0.5) * 0.03;
                    fish.speed = Math.min(MAX_SPEED, Math.max(MIN_SPEED * 0.7, fish.speed));
                }

                // ---- 4. 更新速度向量 ----
                fish.vx = Math.cos(fish.angle) * fish.speed;
                fish.vy = Math.sin(fish.angle) * fish.speed;

                // ---- 5. 移动 ----
                let newX = fish.x + fish.vx;
                let newY = fish.y + fish.vy;

                // 软边界：避免卡在墙上，并稍微弹回
                const softBorder = AVOID_BORDER - 5;
                if (newX < softBorder) { newX = softBorder; fish.angle = Math.PI * 0.1; }
                if (newX > W - softBorder) { newX = W - softBorder; fish.angle = Math.PI * 0.9; }
                if (newY < softBorder) { newY = softBorder; fish.angle = Math.PI * 0.4; }
                if (newY > H - softBorder) { newY = H - softBorder; fish.angle = Math.PI * 1.4; }

                fish.x = newX;
                fish.y = newY;

                // 尾巴相位
                fish.tailPhase += 0.08 + fish.speed * 0.06;

                // ---- 6. 检查是否吃到了食物 ----
                if (targetFood) {
                    const dx = targetFood.x - fish.x;
                    const dy = targetFood.y - fish.y;
                    const dist = Math.sqrt(dx * dx + dy * dy);
                    if (dist < EAT_DISTANCE + targetFood.radius * 0.6) {
                        // 吃掉该食物 (从数组中移除)
                        const idx = foodPellets.indexOf(targetFood);
                        if (idx !== -1) {
                            foodPellets.splice(idx, 1);
                        }
                    }
                }
            }
        }

        // ---------- 绘图 ----------
        function drawScene() {
            ctx.clearRect(0, 0, W, H);

            // ---- 水底波纹/光晕 (氛围) ----
            const grad = ctx.createRadialGradient(120, 100, 20, 300, 200, 700);
            grad.addColorStop(0, 'rgba(150, 215, 255, 0.08)');
            grad.addColorStop(0.5, 'rgba(70, 150, 200, 0.02)');
            grad.addColorStop(1, 'rgba(0, 30, 50, 0)');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, W, H);

            // 水底沙石光点
            ctx.fillStyle = 'rgba(240, 230, 170, 0.04)';
            for (let i=0; i<40; i++) {
                ctx.beginPath();
                ctx.arc(50+ i*23, 560 + Math.sin(i)*8, 3+ i%5, 0, Math.PI*2);
                ctx.fill();
            }

            // ---- 绘制鱼食 (发光粒子) ----
            for (let f of foodPellets) {
                // 光晕
                const glow = ctx.createRadialGradient(f.x, f.y, 1, f.x, f.y, f.radius*3);
                glow.addColorStop(0, 'rgba(255, 210, 100, 0.8)');
                glow.addColorStop(0.5, 'rgba(255, 160, 60, 0.4)');
                glow.addColorStop(1, 'rgba(200, 100, 20, 0)');
                ctx.fillStyle = glow;
                ctx.beginPath();
                ctx.arc(f.x, f.y, f.radius*3, 0, Math.PI*2);
                ctx.fill();

                // 食物实心
                ctx.shadowColor = 'rgba(255, 180, 80, 0.6)';
                ctx.shadowBlur = 12;
                ctx.fillStyle = '#FDB813';
                ctx.beginPath();
                ctx.arc(f.x, f.y, f.radius, 0, Math.PI*2);
                ctx.fill();
                ctx.shadowBlur = 0;
                // 高光
                ctx.fillStyle = 'rgba(255, 240, 180, 0.6)';
                ctx.beginPath();
                ctx.arc(f.x-2, f.y-2, f.radius*0.4, 0, Math.PI*2);
                ctx.fill();
            }

            // ---- 绘制每条鱼 (精致风格) ----
            for (let fish of fishes) {
                const { x, y, angle, size, color, tailPhase } = fish;
                const cosA = Math.cos(angle);
                const sinA = Math.sin(angle);

                ctx.save();
                ctx.translate(x, y);
                ctx.rotate(angle);
                // 鱼体为左右对称，以原点为中心

                // 尾鳍摆动
                const tailWag = Math.sin(tailPhase) * 0.3 + 0.1;

                // ----- 鱼身 (椭圆) -----
                ctx.shadowColor = 'rgba(0, 20, 30, 0.4)';
                ctx.shadowBlur = 12;
                ctx.shadowOffsetY = 2;

                // 身体主色渐变 (随size变化)
                const bodyGrad = ctx.createRadialGradient(-size*0.2, -size*0.2, 2, 0, 0, size*1.2);
                bodyGrad.addColorStop(0, lightenColor(color, 35));
                bodyGrad.addColorStop(0.6, color);
                bodyGrad.addColorStop(1, darkenColor(color, 25));
                ctx.fillStyle = bodyGrad;

                // 鱼身: 椭圆 (中心在原点)
                ctx.beginPath();
                ctx.ellipse(0, 0, size * 0.8, size * 0.45, 0, 0, Math.PI * 2);
                ctx.fill();

                // 腹部亮线
                ctx.shadowBlur = 6;
                ctx.fillStyle = 'rgba(255, 255, 220, 0.2)';
                ctx.beginPath();
                ctx.ellipse(-1, 1, size * 0.5, size * 0.2, 0, 0, Math.PI * 2);
                ctx.fill();

                // ----- 背鳍和腹鳍 (小三角) -----
                ctx.fillStyle = darkenColor(color, 15);
                ctx.shadowBlur = 6;
                // 背鳍
                ctx.beginPath();
                ctx.moveTo(-size*0.1, -size*0.4);
                ctx.lineTo(size*0.1, -size*0.35);
                ctx.lineTo(size*0.2, -size*0.55);
                ctx.closePath();
                ctx.fill();
                // 腹鳍
                ctx.beginPath();
                ctx.moveTo(-size*0.1, size*0.4);
                ctx.lineTo(size*0.1, size*0.35);
                ctx.lineTo(size*0.15, size*0.55);
                ctx.closePath();
                ctx.fill();

                // ----- 尾鳍 (摆动) -----
                ctx.fillStyle = color;
                ctx.shadowBlur = 10;
                ctx.beginPath();
                ctx.moveTo(-size*0.65, -size*0.1);
                ctx.quadraticCurveTo(-size*0.9, -size*0.3 - size*0.2*tailWag, -size*0.75, 0);
                ctx.quadraticCurveTo(-size*0.9, size*0.3 + size*0.2*tailWag, -size*0.65, size*0.1);
                ctx.closePath();
                ctx.fill();

                // 尾鳍透明纹路
                ctx.fillStyle = 'rgba(255,255,230,0.15)';
                ctx.beginPath();
                ctx.moveTo(-size*0.6, -size*0.05);
                ctx.quadraticCurveTo(-size*0.75, -size*0.1, -size*0.7, 0);
                ctx.quadraticCurveTo(-size*0.75, size*0.1, -size*0.6, size*0.05);
                ctx.closePath();
                ctx.fill();

                // ----- 眼睛 (灵性) -----
                ctx.shadowBlur = 0;
                ctx.fillStyle = '#FAFAFA';
                ctx.beginPath();
                ctx.arc(size*0.3, -size*0.12, size*0.14, 0, Math.PI*2);
                ctx.fill();
                ctx.fillStyle = '#0D1B2A';
                ctx.beginPath();
                ctx.arc(size*0.33, -size*0.12, size*0.08, 0, Math.PI*2);
                ctx.fill();
                // 高光
                ctx.fillStyle = 'white';
                ctx.beginPath();
                ctx.arc(size*0.36, -size*0.16, size*0.04, 0, Math.PI*2);
                ctx.fill();

                // 嘴部小点
                ctx.fillStyle = '#3F2B1C';
                ctx.beginPath();
                ctx.arc(size*0.65, 0, size*0.05, 0, Math.PI*2);
                ctx.fill();

                ctx.restore();
            }

            // 水底气泡 (装饰)
            ctx.fillStyle = 'rgba(200, 240, 255, 0.1)';
            for (let i=0; i<12; i++) {
                const bx = 80 + i*70 + Math.sin(Date.now()*0.001 + i)*20;
                const by = 480 - i*25 + Math.sin(Date.now()*0.002 + i*2)*10;
                ctx.beginPath();
                ctx.arc(bx, by, 3+ i%4, 0, Math.PI*2);
                ctx.fill();
            }
        }

        // 工具：颜色变亮/变暗
        function lightenColor(hex, percent) {
            const num = parseInt(hex.slice(1), 16);
            const r = Math.min(255, (num >> 16) + percent);
            const g = Math.min(255, ((num >> 8) & 0x00FF) + percent);
            const b = Math.min(255, (num & 0x0000FF) + percent);
            return `rgb(${r},${g},${b})`;
        }
        function darkenColor(hex, percent) {
            const num = parseInt(hex.slice(1), 16);
            const r = Math.max(0, (num >> 16) - percent);
            const g = Math.max(0, ((num >> 8) & 0x00FF) - percent);
            const b = Math.max(0, (num & 0x0000FF) - percent);
            return `rgb(${r},${g},${b})`;
        }

        // ---------- 动画循环 ----------
        function animate() {
            updateFish();
            drawScene();
            requestAnimationFrame(animate);
        }

        // ---------- 事件绑定（点击投放鱼食）----------
        canvas.addEventListener('click', function(e) {
            const rect = canvas.getBoundingClientRect();
            const scaleX = canvas.width / rect.width;   // canvas物理像素比例
            const scaleY = canvas.height / rect.height;
            const mouseX = (e.clientX - rect.left) * scaleX;
            const mouseY = (e.clientY - rect.top) * scaleY;
            if (mouseX >= 0 && mouseX <= W && mouseY >= 0 && mouseY <= H) {
                addFood(mouseX, mouseY);
            }
        });

        // 触摸设备支持
        canvas.addEventListener('touchstart', function(e) {
            e.preventDefault();
            const rect = canvas.getBoundingClientRect();
            const touch = e.touches[0];
            const scaleX = canvas.width / rect.width;
            const scaleY = canvas.height / rect.height;
            const touchX = (touch.clientX - rect.left) * scaleX;
            const touchY = (touch.clientY - rect.top) * scaleY;
            if (touchX >= 0 && touchX <= W && touchY >= 0 && touchY <= H) {
                addFood(touchX, touchY);
            }
        }, { passive: false });

        // 初始化并运行
        initFish();
        // 开局赠送几粒食物
        for (let i=0; i<5; i++) {
            addFood(150 + Math.random() * 600, 120 + Math.random() * 360);
        }
        animate();
    })();
</script>
</body>
</html>
```
### 核心机制与交互
您可以通过点击水族箱来投放鱼食，并观察鱼儿们有趣的觅食行为。整个动画的交互逻辑和视觉风格都经过了精心设计。

*   **投喂与觅食**：您只需**点击**水族箱内的任意位置，就会在点击处生成一粒发光的鱼食。每条鱼都会智能地**追踪离自己最近的食物**，并在靠近后将其“吃掉”。
*   **自然的鱼群行为**：当没有食物时，鱼儿会进入**自由漫游模式**，并自然地避开边界。它们的游动速度、方向和尾巴摆动都会实时变化，显得生动自然。
*   **精致的视觉风格**：每条鱼都拥有**随机的颜色和大小**，并带有渐变身体、摆动尾鳍和灵动的眼睛。鱼食也带有光晕效果，配合水底的波纹和气泡，营造出沉浸感。

以下是您需要的单文件HTML时钟应用，它拥有简洁高级的表盘，并能动态显示北京时间。
```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>高级白 · 北京时区时钟</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            background: #f5f6fa;
            font-family: 'Segoe UI', 'Inter', system-ui, -apple-system, sans-serif;
        }

        .clock-wrapper {
            background: #ffffff;
            border-radius: 48px;
            padding: 24px;
            box-shadow: 
                0 20px 35px -8px rgba(0, 0, 0, 0.15),
                0 8px 12px -4px rgba(0, 0, 0, 0.05),
                inset 0 1px 2px rgba(255, 255, 255, 0.8);
            transition: box-shadow 0.2s;
            border: 1px solid rgba(0, 0, 0, 0.04);
        }

        .clock-container {
            position: relative;
            width: 380px;
            height: 380px;
            border-radius: 50%;
            background: #ffffff;
            border: 3px solid #1e1e1e;
            box-shadow: 
                0 14px 28px -10px rgba(0, 0, 0, 0.25),
                inset 0 -2px 6px rgba(0, 0, 0, 0.02);
            /* 轻微3D内阴影 */
        }

        canvas#clockCanvas {
            display: block;
            width: 100%;
            height: 100%;
            border-radius: 50%;
            background: transparent;
            /* 确保canvas占满容器 */
        }

        /* 数字与日期使用绝对定位覆盖在canvas之上 (但为了保证视觉, 全部在canvas内绘制)
           但为满足“表盘内部显示当前时间和日期”，我们额外用div叠加在canvas之上，让日期更清晰可读 */
        .date-time-overlay {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            width: 100%;
            height: 100%;
            pointer-events: none;  /* 让点击穿透 */
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
        }

        .digital-time {
            margin-top: 100px;    /* 调整到表盘中心偏下位置 */
            font-size: 22px;
            font-weight: 500;
            letter-spacing: 1px;
            color: #1f1f1f;
            background: rgba(255, 255, 255, 0.65);
            backdrop-filter: blur(2px);
            padding: 4px 14px;
            border-radius: 40px;
            box-shadow: 0 2px 6px rgba(0,0,0,0.03);
            font-variant-numeric: tabular-nums;
            border: 1px solid rgba(200, 200, 200, 0.2);
        }

        .digital-date {
            font-size: 14px;
            font-weight: 400;
            color: #2c2c2c;
            background: rgba(255, 255, 255, 0.5);
            backdrop-filter: blur(1px);
            padding: 3px 16px;
            border-radius: 30px;
            margin-top: 8px;
            letter-spacing: 0.6px;
            border: 1px solid rgba(200, 200, 200, 0.15);
        }

        /* 为了设计更干净，canvas内绘制主要刻度与指针，外部overlay仅显示数字日期 */
        @media (max-width: 480px) {
            .clock-container {
                width: 300px;
                height: 300px;
            }
            .digital-time {
                font-size: 18px;
                margin-top: 75px;
            }
            .digital-date {
                font-size: 12px;
            }
        }
    </style>
</head>
<body>
    <div class="clock-wrapper">
        <div class="clock-container">
            <!-- canvas 负责绘制表盘刻度、时针、分针、秒针 -->
            <canvas id="clockCanvas" width="760" height="760"></canvas>
            <!-- 覆盖层：显示当前时间和日期 (北京时区) -->
            <div class="date-time-overlay">
                <div class="digital-time" id="digitalTime">--:--:--</div>
                <div class="digital-date" id="digitalDate">----年--月--日 周-</div>
            </div>
        </div>
    </div>

    <script>
        (function() {
            "use strict";

            const canvas = document.getElementById('clockCanvas');
            const ctx = canvas.getContext('2d');

            // 适配高清显示
            const dpr = window.devicePixelRatio || 1;
            const size = 380; // 逻辑尺寸
            canvas.width = size * dpr * 2;   // 双倍高清
            canvas.height = size * dpr * 2;
            canvas.style.width = size + 'px';
            canvas.style.height = size + 'px';

            // 绘图半径基准 (基于canvas实际像素)
            const W = canvas.width;
            const H = canvas.height;
            const radius = Math.min(W, H) / 2 - 20 * dpr;  // 留边距
            const centerX = W / 2;
            const centerY = H / 2;

            // DOM 显示时间日期
            const digitalTimeEl = document.getElementById('digitalTime');
            const digitalDateEl = document.getElementById('digitalDate');

            // 星期名称
            const weekNames = ['日', '一', '二', '三', '四', '五', '六'];

            // ---------- 辅助: 获取北京时区时间 ----------
            function getBeijingTime() {
                const now = new Date();
                // 转换为北京时区 (Asia/Shanghai) 通过 locale 或手动偏移
                // 方法: 使用 Intl.DateTimeFormat 获取北京时间 (更可靠)
                const formatter = new Intl.DateTimeFormat('zh-CN', {
                    timeZone: 'Asia/Shanghai',
                    hour: 'numeric', minute: 'numeric', second: 'numeric',
                    hour12: false,
                });
                // 但仍需获得完整时间对象, 可以用偏移计算, 但更稳妥: 分别获取
                const beijingStr = formatter.format(now);
                // 同时获取年月日和星期
                const dateFormatter = new Intl.DateTimeFormat('zh-CN', {
                    timeZone: 'Asia/Shanghai',
                    year: 'numeric', month: '2-digit', day: '2-digit',
                    weekday: 'short',
                });
                const dateParts = dateFormatter.formatToParts(now);
                let year, month, day, weekday;
                for (const part of dateParts) {
                    if (part.type === 'year') year = part.value;
                    else if (part.type === 'month') month = part.value;
                    else if (part.type === 'day') day = part.value;
                    else if (part.type === 'weekday') weekday = part.value;
                }
                // weekday 类似 "周一", 提取数字
                let weekIndex = -1;
                if (weekday) {
                    const ch = weekday.replace('周', '');
                    weekIndex = weekNames.indexOf(ch);
                }
                if (weekIndex === -1) {
                    // fallback: 用getDay
                    weekIndex = now.getDay();
                }

                // 解析小时、分钟、秒 (从beijingStr, 格式: "15:32:08")
                const timeParts = beijingStr.split(':');
                let hours = parseInt(timeParts[0], 10);
                let minutes = parseInt(timeParts[1], 10);
                let seconds = parseInt(timeParts[2], 10);

                // 处理 NaN (极边缘情况)
                if (isNaN(hours)) hours = 0;
                if (isNaN(minutes)) minutes = 0;
                if (isNaN(seconds)) seconds = 0;

                return {
                    year: year || now.getFullYear(),
                    month: month || (now.getMonth() + 1).toString().padStart(2, '0'),
                    day: day || now.getDate().toString().padStart(2, '0'),
                    weekIndex: weekIndex >= 0 ? weekIndex : now.getDay(),
                    hours,
                    minutes,
                    seconds,
                    milliseconds: now.getMilliseconds() // 用于平滑秒针
                };
            }

            // ---------- 绘制表盘 (刻度、数字、logo) ----------
            function drawFace() {
                ctx.clearRect(0, 0, W, H);

                // 外圈深色细环 (增加层次)
                ctx.beginPath();
                ctx.arc(centerX, centerY, radius - 4*dpr, 0, Math.PI * 2);
                ctx.strokeStyle = '#d0d0d0';
                ctx.lineWidth = 1.5 * dpr;
                ctx.stroke();

                // 绘制60个刻度 (整点更粗更深)
                for (let i = 0; i < 60; i++) {
                    const angle = (i * 6 - 90) * Math.PI / 180; // 从12点开始
                    const isHour = (i % 5 === 0);
                    const outerR = isHour ? radius - 14*dpr : radius - 8*dpr;
                    const innerR = isHour ? radius - 28*dpr : radius - 18*dpr;

                    ctx.beginPath();
                    const x1 = centerX + outerR * Math.cos(angle);
                    const y1 = centerY + outerR * Math.sin(angle);
                    const x2 = centerX + innerR * Math.cos(angle);
                    const y2 = centerY + innerR * Math.sin(angle);
                    ctx.moveTo(x1, y1);
                    ctx.lineTo(x2, y2);

                    if (isHour) {
                        ctx.strokeStyle = '#1a1a1a';
                        ctx.lineWidth = 4.5 * dpr;
                    } else {
                        ctx.strokeStyle = '#6b6b6b';
                        ctx.lineWidth = 2 * dpr;
                    }
                    ctx.lineCap = 'round';
                    ctx.stroke();
                }

                // 绘制数字 (1-12) 使用无衬线字体
                ctx.fillStyle = '#1e1e1e';
                ctx.font = `bold ${22*dpr}px "Segoe UI", "Inter", sans-serif`;
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                for (let i = 1; i <= 12; i++) {
                    const angle = (i * 30 - 90) * Math.PI / 180;
                    const numR = radius - 38*dpr;
                    const x = centerX + numR * Math.cos(angle);
                    const y = centerY + numR * Math.sin(angle);
                    ctx.fillText(i.toString(), x, y);
                }

                // 中心小圆点 (装饰)
                ctx.beginPath();
                ctx.arc(centerX, centerY, 8*dpr, 0, Math.PI * 2);
                ctx.fillStyle = '#2b2b2b';
                ctx.shadowColor = 'rgba(0,0,0,0.1)';
                ctx.shadowBlur = 6*dpr;
                ctx.fill();
                ctx.shadowColor = 'transparent';
                // 内圈亮点
                ctx.beginPath();
                ctx.arc(centerX, centerY, 3*dpr, 0, Math.PI * 2);
                ctx.fillStyle = '#f0f0f0';
                ctx.fill();
            }

            // ---------- 更新指针 (时针、分针、秒针) 平滑秒针 ----------
            function updateClock() {
                const bj = getBeijingTime();
                // 平滑秒针: 秒针角度包含毫秒 (6°每秒, 0.006°每毫秒)
                const ms = bj.milliseconds || 0;
                const smoothSeconds = bj.seconds + ms / 1000;
                const secondAngle = (smoothSeconds * 6 - 90) * Math.PI / 180; 

                // 分针: 每分钟6°, 加上秒影响(微动)
                const minuteAngle = ((bj.minutes + bj.seconds / 60) * 6 - 90) * Math.PI / 180;
                // 时针: 每小时30°, 加上分影响
                const hourAngle = ((bj.hours % 12 + bj.minutes / 60) * 30 - 90) * Math.PI / 180;

                // 重新绘制表盘 (避免重绘残留，每一帧完整绘制)
                drawFace();

                // ---- 绘制时针 ----
                const hourLen = radius * 0.5;
                const hourWidth = 8 * dpr;
                ctx.beginPath();
                const hx = centerX + hourLen * Math.cos(hourAngle);
                const hy = centerY + hourLen * Math.sin(hourAngle);
                ctx.moveTo(centerX, centerY);
                ctx.lineTo(hx, hy);
                ctx.strokeStyle = '#1a1a1a';
                ctx.lineWidth = hourWidth;
                ctx.lineCap = 'round';
                ctx.shadowColor = 'rgba(0,0,0,0.12)';
                ctx.shadowBlur = 8*dpr;
                ctx.stroke();

                // ---- 绘制分针 ----
                const minLen = radius * 0.68;
                const minWidth = 5.5 * dpr;
                ctx.beginPath();
                const mx = centerX + minLen * Math.cos(minuteAngle);
                const my = centerY + minLen * Math.sin(minuteAngle);
                ctx.moveTo(centerX, centerY);
                ctx.lineTo(mx, my);
                ctx.strokeStyle = '#2a2a2a';
                ctx.lineWidth = minWidth;
                ctx.lineCap = 'round';
                ctx.shadowColor = 'rgba(0,0,0,0.10)';
                ctx.shadowBlur = 6*dpr;
                ctx.stroke();

                // ---- 绘制秒针 (突出, 亮色) ----
                const secLen = radius * 0.75;
                const secWidth = 2.8 * dpr;
                ctx.beginPath();
                const sx = centerX + secLen * Math.cos(secondAngle);
                const sy = centerY + secLen * Math.sin(secondAngle);
                ctx.moveTo(centerX, centerY);
                ctx.lineTo(sx, sy);
                ctx.strokeStyle = '#d32f2f';
                ctx.shadowColor = 'rgba(211, 47, 47, 0.3)';
                ctx.shadowBlur = 10*dpr;
                ctx.lineWidth = secWidth;
                ctx.lineCap = 'round';
                ctx.stroke();

                // 秒针尾部小圆平衡
                ctx.beginPath();
                const tailR = 6*dpr;
                const tailAngle = secondAngle + Math.PI;
                const tx = centerX + tailR * Math.cos(tailAngle);
                const ty = centerY + tailR * Math.sin(tailAngle);
                ctx.arc(tx, ty, 3.5*dpr, 0, 2 * Math.PI);
                ctx.fillStyle = '#d32f2f';
                ctx.shadowBlur = 6*dpr;
                ctx.fill();

                // 清除阴影避免干扰后续
                ctx.shadowColor = 'transparent';
                ctx.shadowBlur = 0;

                // ---- 更新数字时间与日期 (北京时区) ----
                const hh = bj.hours.toString().padStart(2, '0');
                const mm = bj.minutes.toString().padStart(2, '0');
                const ss = bj.seconds.toString().padStart(2, '0');
                digitalTimeEl.textContent = `${hh}:${mm}:${ss}`;
                const weekStr = `星期${weekNames[bj.weekIndex] || ''}`;
                digitalDateEl.textContent = `${bj.year}年${bj.month}月${bj.day}日 ${weekStr}`;
            }

            // ---------- 驱动动画 (requestAnimationFrame 实现平滑) ----------
            let animId = null;

            function startClock() {
                function tick() {
                    updateClock();
                    animId = requestAnimationFrame(tick);
                }
                if (animId) cancelAnimationFrame(animId);
                tick();
            }

            // 首次启动
            startClock();

            // 页面可视性变化时，保持稳定 (无需额外操作)
            // 窗口尺寸变化不涉及canvas缩放变化，但dpr固定。如果resize可以考虑重绘，但这里保持不变。

            // 暴露给调试 (非必须)
            window.updateClock = updateClock;

            // 兼容 Edge 的被动事件等 (无特殊)
        })();
    </script>
</body>
</html>
```
### 时钟功能与视觉设计

您可以通过这个时钟直观地读取当前时间，其指针和数字均基于北京时区更新。

-   **时间显示与更新**：`updateClock()` 函数负责计算时针、分针和秒针的角度。秒针的运动通过结合毫秒计算，实现了平滑的视觉效果。页面使用 `requestAnimationFrame` 驱动，确保动画流畅。
-   **表盘与刻度绘制**：代码使用 Canvas 动态绘制了60个刻度，其中整点刻度被绘制得更粗、颜色更深，方便您快速辨识。表盘背景为白色，搭配深色边框和细腻的阴影，呈现出您要求的简洁高级感。
-   **日期与时间信息**：表盘中央通过覆盖层清晰显示当前的小时、分钟、秒以及年月日和星期几，所有时间数据均通过 `Intl.DateTimeFormat` 转换为 Asia/Shanghai 时区。

---

**优化建议：** 您可以根据喜好调整 `digital-time` 和 `digital-date` 的 `margin-top` 或 `font-size` 来微调日期时间在表盘内的位置与大小。

```html
<!DOCTYPE html>
<html lang="zh">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>轻量看板 · 个人任务</title>
  <style>
    /* 全局重置 & 字体 */
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
      font-family: system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif;
    }
    body {
      background: #f4f5f7;
      min-height: 100vh;
      padding: 1.5rem 1rem;
