    /* 模态框 (新增/编辑) */
    .modal-overlay {
      position: fixed;
      top: 0; left: 0; width: 100%; height: 100%;
      background: rgba(0,0,0,0.3);
      backdrop-filter: blur(3px);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 999;
      visibility: hidden;
      opacity: 0;
      transition: 0.2s;
    }
    .modal-overlay.active {
      visibility: visible;
      opacity: 1;
    }
    .modal-box {
      background: white;
      width: 90%;
      max-width: 480px;
      padding: 2rem 1.8rem 1.8rem;
      border-radius: 40px;
      box-shadow: 0 20px 40px rgba(0,0,0,0.2);
      display: flex;
      flex-direction: column;
      gap: 1rem;
    }
    .modal-box h3 {
      font-size: 1.6rem;
      font-weight: 400;
      color: #111827;
    }
    .modal-box label {
      display: flex;
      flex-direction: column;
      gap: 0.2rem;
      font-size: 0.9rem;
      color: #1f2937;
    }
    .modal-box input, .modal-box textarea, .modal-box select {
      padding: 0.6rem 1rem;
      border: 1px solid #d1d9e6;
      border-radius: 30px;
      font-size: 0.95rem;
      background: #fafcff;
      outline: none;
    }
    .modal-box textarea {
      min-height: 70px;
      resize: vertical;
      border-radius: 24px;
    }
    .modal-actions {
      display: flex;
