<body>
    <div class="clock" id="clock">
        <!-- scale container (60 ticks) -->
        <div class="scale-container" id="ticks"></div>

        <!-- numbers 1–12 -->
        <div class="number" id="numbers"></div>

        <!-- hands -->
        <div class="hand hour-hand" id="hourHand"></div>
